import{c as a,S as t,j as o,m as i}from"./chunks/framework.BZjfhLWX.js";const u=JSON.parse('{"title":"News","description":"","frontmatter":{},"headers":[],"relativePath":"news.md","filePath":"news.md","lastUpdated":null}'),r={name:"news.md"};function s(n,e,l,d,h,p){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="News" tabindex="-1">News <a class="header-anchor" href="#News" aria-label="Permalink to &quot;News {#News}&quot;">​</a></h1><p>Release notes for BVDOutbreakSize. Major versions of the report are kept as <a href="https://github.com/epiforecasts/BVDOutbreakSize/releases" target="_blank" rel="noreferrer">GitHub Releases</a>; each push to <code>main</code> also republishes the rendered analysis and the <code>output/</code> artifacts.</p><h2 id="v1.1.0" tabindex="-1">v1.1.0 <a class="header-anchor" href="#v1.1.0" aria-label="Permalink to &quot;v1.1.0 {#v1.1.0}&quot;">​</a></h2><h3 id="Modelling" tabindex="-1">Modelling <a class="header-anchor" href="#Modelling" aria-label="Permalink to &quot;Modelling {#Modelling}&quot;">​</a></h3><ul><li><p>Bound the seeding time <code>T</code> from below with a soft prior on the genetic time to the most recent common ancestor (TMRCA). Inspired by an estimate from Neil Ferguson, using the first eight BDBV genomes reported on <a href="https://virological.org/t/initial-genomes-from-may-2026-bundibugyo-virus-disease-outbreak-in-the-democratic-republic-of-the-congo-and-uganda/1032" target="_blank" rel="noreferrer">virological.org</a>.</p></li><li><p>Switched the export deaths to a daily (time-resolved binned) Poisson process: a continuous survival weight for the no-death stretch before the first dated death, then a per-day Poisson from that day to the cut-off.</p></li><li><p>Bound <code>T</code> with export-death timing through that survival weight, and with case-export detection timing through a first-export-detection survival term on the Uganda admission date. Dates supplied in <code>data/observations.toml</code>.</p></li><li><p>Death-convolution quadrature adapted to the sampled delay scale.</p></li><li><p>Removed hardcoded death and case constants that diverged from the observations in <code>data/observations.toml</code>.</p></li></ul><h3 id="Data" tabindex="-1">Data <a class="header-anchor" href="#Data" aria-label="Permalink to &quot;Data {#Data}&quot;">​</a></h3><ul><li>Updated to the McCabe et al. 20 May 2026 report, comparing both report versions.</li></ul><h3 id="Infrastructure" tabindex="-1">Infrastructure <a class="header-anchor" href="#Infrastructure" aria-label="Permalink to &quot;Infrastructure {#Infrastructure}&quot;">​</a></h3><ul><li><p>Dropped MCMCChains for FlexiChains and prepared for registry release.</p></li><li><p>CI docs preview PR comments and version-bump automation.</p></li></ul><h3 id="Docs" tabindex="-1">Docs <a class="header-anchor" href="#Docs" aria-label="Permalink to &quot;Docs {#Docs}&quot;">​</a></h3><ul><li><p>Added a scope note to the README and analysis report framing the work as an external view built on our understanding of real-time infectious disease dynamics, and inviting feedback, reuse and adaptation.</p></li><li><p>Surfaced results from the README and analysis landing page, added stable and dev docs badges.</p></li><li><p>Plotting and labelling fixes: surveillance dispersion on the 1/√k scale, predictive histograms labelled as frequency, model diagram width.</p></li><li><p>Culled promotional register in the analysis report.</p></li></ul><h2 id="v1.0.0" tabindex="-1">v1.0.0 <a class="header-anchor" href="#v1.0.0" aria-label="Permalink to &quot;v1.0.0 {#v1.0.0}&quot;">​</a></h2><p>First release. A joint Bayesian re-analysis of the McCabe et al. report that fits all data streams together in a single Turing model over the latent cumulative case count.</p><ul><li><p>Conditions on the exported cases and DRC deaths the report uses, plus reported DRC cases (with an ascertainment component) and deaths among exported cases.</p></li><li><p>Adds a no-onward-transmission projected-deaths counterfactual, a one-week-ahead forecast of newly reported cases, deaths and exports, and an onset-to-death delay sensitivity analysis.</p></li><li><p>Replaces the deaths-convolution and small-growth-rate exports closed-form approximations with their exact forms.</p></li><li><p>Maths-first analysis page with code folded behind dropdowns and a diagram of the model build-up.</p></li><li><p>Compares against a joint reimplementation of the report&#39;s approach and its original published estimates.</p></li></ul>',14)])])}const m=a(r,[["render",s]]);export{u as __pageData,m as default};
